@@ -93,3 +95,127 @@ define i1 @test5(i32 %i, ptr %p) {
   ret i1 %op
 }

+define i1 @fold_lshr_power_of_2(i8 %x) {
+; CHECK-LABEL: define i1 @fold_lshr_power_of_2(
+; CHECK-SAME: i8 [[X:%.*]]) {
+; CHECK-NEXT:    [[TRUNC:%.*]] = icmp eq i8 [[X]], 4
+; CHECK-NEXT:    ret i1 [[TRUNC]]
